import NextAuth from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import { prisma } from "@/lib/prisma";
import { cmsPrisma } from "@/lib/prisma-cms";

export const { handlers, auth, signIn, signOut } = NextAuth({
  providers: [
    CredentialsProvider({
      name: "credentials",
      credentials: {
        loginType:  { label: "Login Type", type: "text" },
        identifier: { label: "ID",         type: "text" },
        dob:        { label: "Birthdate",  type: "text" },
        pin:        { label: "PIN",        type: "text" },
      },
      async authorize(credentials) {
        const loginType  = credentials?.loginType  as string;
        const identifier = (credentials?.identifier as string)?.trim();
        const dob        = credentials?.dob        as string;
        const pin        = (credentials?.pin        as string)?.trim();

        if (!loginType || !identifier || !dob) {
          throw new Error("Missing credentials");
        }

        // ── PATIENT LOGIN: patientCode + dob ──────────────────────────
        if (loginType === "patient") {
          // Look up portal user by patientCode
          const user = await prisma.portalUser.findUnique({
            where: { patientCode: identifier },
          });

          if (!user) throw new Error("No account found with this Patient ID");
          if (!user.isActive || user.deletedAt) throw new Error("Your account has been deactivated");

          // Verify DOB matches CMS patient record
          const cmsPatient = await cmsPrisma.cmsPatient.findUnique({
            where: { code: identifier },
            select: { dob: true },
          });

          if (!cmsPatient) throw new Error("Patient record not found in system");

          const inputDob   = new Date(dob);
          const cmsDob     = new Date(cmsPatient.dob);
          const dobMatches =
            inputDob.getFullYear() === cmsDob.getFullYear() &&
            inputDob.getMonth()    === cmsDob.getMonth() &&
            inputDob.getDate()     === cmsDob.getDate();

          if (!dobMatches) throw new Error("Incorrect date of birth");

          await prisma.portalUser.update({
            where: { id: user.id },
            data: { lastLoginAt: new Date() },
          });

          return {
            id: user.id,
            email: user.email,
            name: `${user.firstName} ${user.lastName}`,
            firstName: user.firstName,
            lastName: user.lastName,
            mobile: user.mobile,
            patientCode: user.patientCode ?? undefined,
            role: user.role,
          };
        }

        // ── HR LOGIN: hrCode + dob + 3-digit PIN ──────────────────────
        if (loginType === "hr") {
          if (!pin || !/^\d{3}$/.test(pin)) {
            throw new Error("Invalid PIN format — must be 3 digits");
          }

          const user = await prisma.portalUser.findUnique({
            where: { hrCode: identifier },
          });

          if (!user) throw new Error("No HR account found with this ID");
          if (!user.isActive || user.deletedAt) throw new Error("Your account has been deactivated");
          if (user.role !== "HR" && user.role !== "ADMIN") throw new Error("Unauthorized role");

          // Verify DOB matches portal user record
          const inputDob   = new Date(dob);
          const storedDob  = new Date(user.dob);
          const dobMatches =
            inputDob.getFullYear() === storedDob.getFullYear() &&
            inputDob.getMonth()    === storedDob.getMonth() &&
            inputDob.getDate()     === storedDob.getDate();

          if (!dobMatches) throw new Error("Incorrect date of birth");

          // Verify 3-digit PIN
          if (user.pin !== pin) throw new Error("Incorrect PIN");

          await prisma.portalUser.update({
            where: { id: user.id },
            data: { lastLoginAt: new Date() },
          });

          return {
            id: user.id,
            email: user.email,
            name: `${user.firstName} ${user.lastName}`,
            firstName: user.firstName,
            lastName: user.lastName,
            mobile: user.mobile,
            patientCode: undefined,
            role: user.role,
          };
        }

        throw new Error("Invalid login type");
      },
    }),
  ],
  session: {
    strategy: "jwt",
    maxAge: 30 * 24 * 60 * 60, // 30 days
  },
  pages: {
    signIn: "/login",
    error: "/login",
  },
  callbacks: {
    async jwt({ token, user }) {
      if (user) {
        token.id = user.id;
        token.firstName = (user as { firstName?: string }).firstName;
        token.lastName = (user as { lastName?: string }).lastName;
        token.mobile = (user as { mobile?: string }).mobile;
        token.patientCode = (user as { patientCode?: string }).patientCode;
        token.role = (user as { role?: string }).role;
      }
      return token;
    },
    async session({ session, token }) {
      if (token) {
        session.user.id = token.id as string;
        session.user.firstName = token.firstName as string;
        session.user.lastName = token.lastName as string;
        session.user.mobile = token.mobile as string;
        session.user.patientCode = token.patientCode as string | undefined;
        session.user.role = token.role as string;
      }
      return session;
    },
  },
  secret: process.env.AUTH_SECRET,
  trustHost: true,
});

declare module "next-auth" {
  interface User {
    id?: string;
    firstName?: string;
    lastName?: string;
    mobile?: string;
    patientCode?: string;
    role?: string;
  }

  interface Session {
    user: {
      id: string;
      email: string;
      name: string;
      firstName: string;
      lastName: string;
      mobile: string;
      patientCode?: string;
      role: string;
    };
  }

  interface JWT {
    id?: string;
    firstName?: string;
    lastName?: string;
    mobile?: string;
    patientCode?: string;
    role?: string;
  }
}
